#cp-content-2 .lesson-modular {
  height: 44px;
  padding: 11px 12px 7px 12px;
  gap: 6px;
  border-bottom: 1px solid var(--border-border-subtle, #d1cfc5) !important;
}

#returnToOverview {
  padding-bottom: 20px;
  font-size: 18px;
  text-decoration: underline;
  font-family: "Styrene B";
  color: #615f5b !important;
}

